      ~Threaded_Fork() override;

      Threaded_Fork(const Threaded_Fork& other) = delete;
      Threaded_Fork(Threaded_Fork&& other) = delete;
      Threaded_Fork& operator=(const Threaded_Fork& other) = delete;
